import numpy as np

def select_next_node(current_node, truck_nodes, depot_node, unvisited_nodes, distance_matrix):
    """
    {The algorithm selects the next node based on a combination of direct distance attraction, congestion avoidance by measuring node centrality, and dynamic adjustment using truck dispersion index across the network.}
    """
    # Step 1: Direct distance attraction for unvisited nodes.
    direct_distances = {node: distance_matrix[current_node, node] for node in unvisited_nodes}

    # Step 2: Calculate node centrality to avoid congested nodes.
    centrality = {node: np.sum(distance_matrix[:, node]) for node in unvisited_nodes}

    # Step 3: Compute truck dispersion index to dynamically prefer dispersed routes.
    unique_truck_nodes = len(set(truck_nodes))
    network_dispersion = {node: unique_truck_nodes / (1 + np.sum(truck_nodes == node)) for node in unvisited_nodes}

    # Step 4: Compute a new score by balancing the above components.
    scores = {
        node: (0.3 * direct_distances[node] +
               0.4 * (1.0 / (centrality[node] + 1.e-5)) +
               0.3 * network_dispersion[node])
        for node in unvisited_nodes
    }

    # Step 5: Select the node with the highest score.
    next_node = min(scores, key=scores.get)

    return next_node
